### Phase 2: Configuration Loader Module (3 hours)

**Objective**: Create runtime composition layer with template inheritance support

**File**: `packages/classification-engine/src/config/config-composer.ts`

**Architecture**:

```typescript
/**
 * Configuration Composer - Runtime composition with template inheritance
 *
 * Load order:
 * 1. Load category template (_base/category-template.json)
 * 2. Load global fragments (settings, attributes, ai_config, domains)
 * 3. Load category fragments (categories/*.json)
 * 4. Apply template inheritance (merge category + template)
 * 5. Compose into final CategoryConfiguration object
 * 6. Validate against existing Zod schema
 * 7. Cache in-memory (invalidate on any fragment change)
 */

export interface ComposerOptions {
  configDir?: string;
  enableCaching?: boolean;
  cacheTtlMs?: number;
}

export class ConfigurationComposer {
  private templateCache: CategoryTemplate | null = null;
  private composedConfigCache: CategoryConfiguration | null = null;
  private fragmentHashes: Map<string, string> = new Map();

  /**
   * Main composition function - assembles final config from fragments
   */
  async composeConfiguration(): Promise<CategoryConfiguration> {
    // 1. Check cache validity (compare file hashes)
    if (await this.isCacheValid()) {
      return this.composedConfigCache!;
    }

    // 2. Load all fragments in parallel
    const [template, settings, attributes, aiConfig, domains, categories] = await Promise.all([
      this.loadCategoryTemplate(),
      this.loadSettings(),
      this.loadAttributes(),
      this.loadAiConfig(),
      this.loadDomains(),
      this.loadCategories(),
    ]);

    // 3. Apply template inheritance to categories
    const inheritedCategories = categories.map((cat) => this.applyTemplateInheritance(cat, template));

    // 4. Compose final configuration object
    const composed = this.assembleConfiguration({
      settings,
      attributes,
      aiConfig,
      domains,
      categories: inheritedCategories,
    });

    // 5. Validate against existing schema
    const validated = validateCategoryConfiguration(composed);

    // 6. Cache result
    this.composedConfigCache = validated;
    await this.updateFragmentHashes();

    return validated;
  }

  /**
   * Apply template inheritance with merge strategy
   */
  private applyTemplateInheritance(category: CategoryFragment, template: CategoryTemplate): CategoryDefinition {
    const merged = { ...template.structure };

    for (const [field, strategy] of Object.entries(template.mergeStrategy)) {
      if (field in category) {
        if (strategy === 'override') {
          merged[field] = category[field];
        } else if (strategy === 'merge-deep') {
          merged[field] = this.deepMerge(merged[field], category[field]);
        }
      }
    }

    return merged as CategoryDefinition;
  }

  /**
   * Deep merge with category-specific overrides
   */
