    // Implementation: recursive merge with array override (not concat)
    // ...
  }

  /**
   * Load individual fragments (parallel-safe)
   */
  private async loadCategoryTemplate(): Promise<CategoryTemplate> {
    /* ... */
  }
  private async loadSettings(): Promise<GlobalSettings> {
    /* ... */
  }
  private async loadAttributes(): Promise<AttributeDefinitions> {
    /* ... */
  }
  private async loadAiConfig(): Promise<AiConfiguration> {
    /* ... */
  }
  private async loadDomains(): Promise<DomainConfiguration> {
    /* ... */
  }
  private async loadCategories(): Promise<CategoryFragment[]> {
    // Reads all files from categories/ directory
    // Returns array of category fragments
  }

  /**
   * Assemble final configuration object
   */
  private assembleConfiguration(fragments: AllFragments): CategoryConfiguration {
    return {
      version: '2.0.0',
      lastModified: new Date().toISOString(),
      hash: this.calculateComposedHash(fragments),
      processingConfig: {
        version: 2,
        settings: fragments.settings,
        attributes: fragments.attributes,
        aiConfig: fragments.aiConfig,
        domainConfig: fragments.domains,
        topLevelCategories: this.categoriesToObject(fragments.categories),
        categorySignals: this.buildCategorySignals(fragments.categories),
      },
    };
  }

  /**
   * Cache validation - check if any fragment changed
   */
  private async isCacheValid(): Promise<boolean> {
    if (!this.composedConfigCache) return false;

    const files = await this.getAllFragmentFiles();
    for (const file of files) {
      const currentHash = await this.calculateFileHash(file);
      const cachedHash = this.fragmentHashes.get(file);
      if (currentHash !== cachedHash) return false;
    }

    return true;
  }
}

/**
 * Integration with existing ConfigurationLoader
 */
export async function loadCategoryConfigurationModular(
  options?: ComposerOptions
): Promise<ConfigLoadResult<CategoryConfiguration>> {
  const composer = new ConfigurationComposer(options);
  const config = await composer.composeConfiguration();

  // Return in ConfigLoadResult format for compatibility
  return {
    config,
    hash: config.hash,
    lastModified: new Date(config.lastModified),
    validationPassed: true,
    validationErrors: [],
    loadTime: 0, // Tracked separately
  };
}
```

**Error Handling Strategy**:

1. **Missing Files**: Clear error message with expected path
2. **Invalid JSON**: Parse error with file name and line number
3. **Schema Validation Failures**: Structured validation errors from Zod
4. **Broken Cross-References**: E.g., category references undefined domain group
5. **Template Inheritance Errors**: E.g., required override not provided

